function oma_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function oma_num($v,$d=5){return number_format((float)$v,$d,',','.');}
function oma_pct($a,$b){$b=(float)$b;return $b>0?max(0,min(999,round(((float)$a/$b)*100,1))):0;}
function oma_status_text($s){$m=array('NO_CONFIRMATION'=>'production_no_confirmation','WAITING_GR'=>'production_waiting_gr','PARTIAL_GR'=>'production_partial_gr','COMPLETED'=>'production_completed','OVER_GR'=>'production_over_gr');return prod_t(isset($m[$s])?$m[$s]:'',$s);}
$act=isset($_GET['act'])?$_GET['act']:'';
switch($act){
  case 'detail':
    $id=isset($_POST['id'])?(int)$_POST['id']:0;$po=$db->fetch("SELECT * FROM production_order WHERE id_production_order=? LIMIT 1",array($id));
