    $confs=$db->query("SELECT * FROM production_order_confirmation WHERE id_production_order=? ORDER BY posting_date,id_confirmation",array($id));
    $grs=$db->query("SELECT h.*,d.material_code,d.material_name,d.qty,d.uom,d.stock_layer_id,ep.plant_code,es.storage_code,eb.bin_code FROM erp_gr_production h JOIN erp_gr_production_detail d ON d.gr_id=h.id LEFT JOIN erp_plant ep ON ep.id=h.plant_id LEFT JOIN erp_storage_location es ON es.id=h.storage_location_id LEFT JOIN erp_storage_bin eb ON eb.id=h.storage_bin_id WHERE h.id_production_order=? ORDER BY h.posting_date,h.id",array($id));
    $trace=$db->query("SELECT h.gr_no,tr.raw_material_code,tr.raw_material_name,tr.qty,tr.uom,tr.lot_no,tr.no_bpb,tr.jenis_dokpab,tr.no_aju,tr.no_dokpab,tr.trace_source FROM erp_gr_production_trace tr JOIN erp_gr_production h ON h.id=tr.gr_id WHERE h.id_production_order=? ORDER BY h.gr_no,tr.raw_material_code,tr.id LIMIT 100",array($id));
    $outstanding=(float)$sum->yield_qty-(float)$sum->gr_qty;
    echo '<h3 style="margin-top:0">'.oma_h($po->no_production_order).' <small>'.oma_h($po->status.' / '.$po->priority).'</small></h3><div class="row"><div class="col-sm-4"><strong>'.prod_h('production_material','Material').'</strong><br>'.oma_h($po->material_code.' - '.$po->material_name).'</div><div class="col-sm-2"><strong>'.prod_h('production_order_qty','Order Qty').'</strong><br>'.oma_num($po->order_qty).' '.oma_h($po->uom).'</div><div class="col-sm-2"><strong>'.prod_h('production_yield_gr','Yield / GR').'</strong><br>'.oma_num($sum->yield_qty).' / '.oma_num($sum->gr_qty).'</div><div class="col-sm-2"><strong>'.prod_h('production_outstanding','Outstanding').'</strong><br>'.oma_num($outstanding).'</div><div class="col-sm-2"><strong>'.prod_h('production_plant_sloc','Plant/SLoc').'</strong><br>'.oma_h($po->plant.' / '.$po->storage_location).'</div></div><hr>';
    echo '<h4>'.prod_h('production_confirmations','Confirmations').'</h4><table class="table table-bordered table-condensed"><thead><tr class="bg-gray"><th>'.prod_h('production_confirmation_short','Confirmation').'</th><th>'.prod_h('production_posting','Posting').'</th><th>'.prod_h('production_operation','Operation').'</th><th>'.prod_h('production_operator','Operator').'</th><th class="text-right">'.prod_h('production_yield','Yield').'</th><th class="text-right">'.prod_h('production_scrap','Scrap').'</th><th class="text-right">'.prod_h('production_rework','Rework').'</th><th>'.prod_h('common_status','Status').'</th></tr></thead><tbody>';
    foreach($confs as $c)echo '<tr><td>'.oma_h($c->confirmation_no).'</td><td>'.oma_h($c->posting_date).'</td><td>'.oma_h($c->operation_no.' / '.$c->work_center).'</td><td>'.oma_h($c->operator_name).'</td><td class="text-right">'.oma_num($c->yield_qty).'</td><td class="text-right">'.oma_num($c->scrap_qty).'</td><td class="text-right">'.oma_num($c->rework_qty).'</td><td>'.oma_h($c->status).'</td></tr>';
    echo '</tbody></table><h4>'.prod_h('production_gr_from_production_order','GR from Production Order').'</h4><table class="table table-bordered table-condensed"><thead><tr class="bg-gray"><th>'.prod_h('production_gr_short','GR').'</th><th>'.prod_h('production_posting','Posting').'</th><th>'.prod_h('production_confirmation_short','Confirmation').'</th><th>'.prod_h('production_material','Material').'</th><th>'.prod_h('warehouse_location','Location').'</th><th class="text-right">'.prod_h('production_qty','Qty').'</th><th>'.prod_h('common_status','Status').'</th></tr></thead><tbody>';
    foreach($grs as $g)echo '<tr><td>'.oma_h($g->gr_no).'</td><td>'.oma_h($g->posting_date).'</td><td>'.oma_h($g->confirmation_no).'</td><td><strong>'.oma_h($g->material_code).'</strong><br><small>'.oma_h($g->material_name).'</small></td><td>'.oma_h(trim($g->plant_code.' / '.$g->storage_code.' / '.$g->bin_code,' /')).'</td><td class="text-right">'.oma_num($g->qty).' '.oma_h($g->uom).'</td><td>'.oma_h($g->status).'</td></tr>';
